#include <bits/stdc++.h>
using namespace std;

const int N = 5e5 + 10;

struct Node {
    int l, m, r;
} a[N];

bool operator<(Node x, Node y) {
    return x.l < y.l;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    int t;
    cin >> t;
    while (t--) {
        int n, k;
        cin >> n >> k;
        for (int i = 0; i < k; ++i) {
            cin >> a[i].l >> a[i].m >> a[i].r;
        }
        sort(a, a + k);
        int covered = 0;
        bool possible = true;
        for (int i = 0; i < k && possible; ++i) {
            if (a[i].m > covered + 1) {
                possible = false;
                break;
            }
            if (a[i].l <= covered + 1) {
                covered = max(covered, a[i].r);
            }
        }
        if (covered < n) {
            possible = false;
        }
        cout << (possible ? "YES" : "NO") << '\n';
    }
    return 0;
}
